// src/components/Search.js
import React, { useState } from 'react';
import axios from 'axios';

const Search = ({ onSearch }) => {
  const [district, setDistrict] = useState('');
  const [taluka, setTaluka] = useState('');
  const [surveyNumber, setSurveyNumber] = useState('');
  const [captcha, setCaptcha] = useState('');
  const [language, setLanguage] = useState('marathi');

  const handleSearch = async () => {
    try {
      // Log the form data to see the parameters
      console.log({ district, taluka, surveyNumber, captcha, language });

      // Call the backend API to search land records
      const response = await axios.get(`http://127.0.0.1:8000/api/search/`, {
        params: {
          district,
          taluka,
          survey_number: surveyNumber,
          captcha,
          language,
        },
      });

      // Pass the data to the parent component
      onSearch(response.data);
    } catch (error) {
      console.error('Error during the search:', error);
    }
  };

  return (
    <div>
      <h2>Search Land Records</h2>
      <form>
        {/* District */}
        <div>
          <label>District</label>
          <select
            value={district}
            onChange={(e) => setDistrict(e.target.value)}
          >
            <option value="">--Select District--</option>
            <option value="Akola">Akola</option>
            <option value="Amravati">Amravati</option>
            <option value="Buldhana">Buldhana</option>
            {/* Add more districts as needed */}
          </select>
        </div>

        {/* Taluka */}
        <div>
          <label>Taluka</label>
          <select
            value={taluka}
            onChange={(e) => setTaluka(e.target.value)}
          >
            <option value="">--Select Taluka--</option>
            <option value="Akola Taluka">Akola Taluka</option>
            <option value="Amravati Taluka">Amravati Taluka</option>
            <option value="Buldhana Taluka">Buldhana Taluka</option>
            {/* Add more talukas as needed */}
          </select>
        </div>

        {/* Survey Number */}
        <div>
          <label>Survey Number</label>
          <input
            type="text"
            value={surveyNumber}
            onChange={(e) => setSurveyNumber(e.target.value)}
            placeholder="Enter Survey Number"
          />
        </div>

        {/* Captcha */}
        <div>
          <label>Captcha</label>
          <input
            type="text"
            value={captcha}
            onChange={(e) => setCaptcha(e.target.value)}
            placeholder="Enter Captcha"
          />
          <img src="captcha.png" alt="Captcha" /> {/* Replace with actual captcha image */}
        </div>

        {/* Language Selector */}
        <div>
          <label>Select Language</label>
          <select
            value={language}
            onChange={(e) => setLanguage(e.target.value)}
          >
            <option value="marathi">Marathi</option>
            <option value="english">English</option>
            {/* Add more languages as needed */}
          </select>
        </div>

        {/* Search Button */}
        <button type="button" onClick={handleSearch}>
          Search
        </button>
      </form>
    </div>
  );
};

export default Search;
